import React, { Component, memo } from "react";
import Typical from "react-typical";
import { motion, AnimatePresence } from "framer-motion";

// MEMOIZED COMPONENT: Prevents Typical from lagging/restarting
const AnimatedTitles = memo(({ titles }) => {
  return <Typical className="title-styles" steps={titles} loop={Infinity} />;
}, (prevProps, nextProps) => {
  return JSON.stringify(prevProps.titles) === JSON.stringify(nextProps.titles);
});

class Header extends Component {
  constructor() {
    super();
    this.state = { 
      checked: false,
      isScrolled: false 
    };
    this.toggleTheme = this.toggleTheme.bind(this);
  }

  componentDidMount() {
    const currentTheme = document.body.getAttribute("data-theme");
    this.setState({ checked: currentTheme === "dark" });
    window.addEventListener("scroll", this.handleScroll, { passive: true });
  }

  componentWillUnmount() {
    window.removeEventListener("scroll", this.handleScroll);
  }

  handleScroll = () => {
    const isScrolled = window.scrollY > 50;
    if (isScrolled !== this.state.isScrolled) {
      this.setState({ isScrolled });
    }
  };

  // Optimization: Only re-render if essential state/props change
  shouldComponentUpdate(nextProps, nextState) {
    return (
      nextState.checked !== this.state.checked ||
      nextState.isScrolled !== this.state.isScrolled ||
      nextProps.sharedData !== this.props.sharedData
    );
  }

  toggleTheme() {
    const newChecked = !this.state.checked;
    this.setState({ checked: newChecked }, () => {
      this.setTheme(newChecked);
    });
  }

  setTheme(checked) {
    const dataThemeAttribute = "data-theme";
    const body = document.body;
    const newTheme = checked ? "dark" : "light";
    body.setAttribute(dataThemeAttribute, newTheme);
  }

  scrollToSection = (e, id) => {
    e.preventDefault();
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({
        behavior: "smooth",
        block: "start", 
      });
    }
  };

  // Robust Language Switcher logic
  handleLanguageChange = (lang, icon) => {
    if (this.props.applyPickedLanguage) {
      this.props.applyPickedLanguage(lang, icon);
    }
  };

  render() {
    let name = "";
    let titles = [];
    const { isScrolled, checked } = this.state;

    const navItems = [
      { id: "about", name: this.props.resumeBasicInfo?.section_name?.about || "About" },
      { id: "portfolio", name: this.props.resumeBasicInfo?.section_name?.projects || "Projects" },
      { id: "skills", name: this.props.resumeBasicInfo?.section_name?.skills || "Skills" },
      { id: "resume", name: this.props.resumeBasicInfo?.section_name?.experience || "Experience" },
      { id: "contact", name: "Contact" }
    ];

    if (this.props.sharedData) {
      name = this.props.sharedData.name;
      titles = this.props.sharedData.titles.map(x => [x.toUpperCase(), 1500]).flat();
    }

    const containerVariants = {
      hidden: { opacity: 0, y: 30 },
      visible: { 
        opacity: 1, 
        y: 0,
        transition: { duration: 0.8, ease: "easeOut", staggerChildren: 0.2 }
      }
    };

    const childVariants = {
      hidden: { opacity: 0, y: 20 },
      visible: { opacity: 1, y: 0 }
    };

    return (
      <header id="home" style={{ 
        height: '100vh', 
        minHeight: '600px',
        display: 'block',
        background: 'var(--body-background)',
        transition: 'background-color 0.6s ease',
        position: 'relative',
        overflow: 'hidden'
      }}>

        {/* TOP LEFT GITHUB CORNER */}
        <a href="https://github.com" target="_blank" rel="noopener noreferrer" className="github-corner">
          <svg width="90" height="90" viewBox="0 0 250 250" style={{ fill: '#AE944F', color: '#fff', position: 'absolute', top: 0, left: 0, border: 0, transform: 'scaleX(-1)', zIndex: 1001 }}>
            <path d="M0,0 L115,115 L130,115 L142,142 L250,250 L250,0 Z"></path>
            <path d="M128.3,109.0 C113.8,99.7 119.0,89.6 119.0,89.6 C122.0,82.7 120.5,78.6 120.5,78.6 C119.2,72.0 123.4,76.3 123.4,76.3 C127.3,80.9 125.5,87.3 125.5,87.3 C122.9,97.6 130.6,101.9 134.4,103.2" fill="currentColor" style={{ transformOrigin: '130px 106px' }} className="octo-arm"></path>
            <path d="M115.0,115.0 C114.9,115.1 118.7,116.5 119.8,115.4 L133.7,101.6 C136.9,99.2 139.9,98.4 142.2,98.6 C133.8,88.0 127.5,74.4 143.8,58.0 C148.5,53.3 154.0,51.2 159.7,51.0 C160.3,49.4 163.2,43.6 171.4,40.1 C171.4,40.1 176.1,42.5 178.8,56.2 C183.1,58.6 187.2,61.8 190.9,65.4 C194.5,69.0 197.7,73.2 200.1,77.6 C213.8,80.2 216.3,84.9 216.3,84.9 C212.7,93.1 206.9,96.0 205.4,96.6 C205.1,102.4 203.0,107.8 198.3,112.5 C181.9,128.9 168.3,122.5 157.7,114.1 C157.9,116.9 156.7,120.9 152.7,124.9 L141.0,136.5 C139.8,137.7 141.6,141.9 141.8,141.8 Z" fill="currentColor" className="octo-body"></path>
          </svg>
        </a>

        {/* ADAPTIVE STICKY NAV */}
        <motion.nav 
          initial={false}
          animate={{
            backgroundColor: isScrolled ? "rgba(10, 10, 10, 0.9)" : "rgba(0, 0, 0, 0)",
            padding: isScrolled ? "10px 50px" : "25px 50px",
            boxShadow: isScrolled ? "0 10px 30px rgba(0,0,0,0.4)" : "none"
          }}
          style={{
            position: "fixed", top: 0, right: 0, width: "100%", zIndex: 1000,
            display: "flex", justifyContent: "flex-end", alignItems: "center",
            backdropFilter: isScrolled ? "blur(10px)" : "none",
            transition: "padding 0.4s ease, background-color 0.4s ease"
          }}
        >
          {navItems.map((item) => (
            <motion.button
              key={item.id}
              onClick={(e) => this.scrollToSection(e, item.id)}
              style={{
                background: "none", border: "none", cursor: "pointer",
                color: isScrolled ? "#FFFFFF" : "var(--header-text)",
                fontSize: "0.85rem", fontWeight: "600",
                textTransform: "uppercase", letterSpacing: "1.5px",
                margin: "0 12px", padding: "8px 12px", borderRadius: "8px"
              }}
              whileHover={{ color: "#AE944F" }}
            >
              {item.name}
            </motion.button>
          ))}

          {/* LANGUAGE & THEME CONTROLS */}
          <div style={{ display: 'flex', alignItems: 'center', marginLeft: '20px' }}>

            {/* LANGUAGE FLAGS */}
            <div 
              className="language-selector" 
              style={{ display: 'flex', gap: '15px', marginRight: '20px' }}
            >
              <div
                onClick={() => this.handleLanguageChange(window.$primaryLanguage, window.$primaryLanguageIcon)}
                style={{ cursor: "pointer" }}
                title="English"
              >
                <span className="iconify language-icon" data-icon="twemoji:flag-united-kingdom" data-inline="false" style={{ fontSize: '24px' }}></span>
              </div>
              <div
                onClick={() => this.handleLanguageChange(window.$secondaryLanguage, window.$secondaryLanguageIcon)}
                style={{ cursor: "pointer" }}
                title="Hindi"
              >
                <span className="iconify language-icon" data-icon="twemoji:flag-india" data-inline="false" style={{ fontSize: '24px' }}></span>
              </div>
            </div>

            {/* THEME ICON BUTTON */}
            <motion.div 
              onClick={this.toggleTheme}
              style={{ 
                cursor: 'pointer', fontSize: '26px', 
                display: 'flex', alignItems: 'center', color: '#AE944F',
                position: 'relative', width: '30px', height: '30px',
                justifyContent: 'center'
              }}
            >
              <AnimatePresence mode="wait" initial={false}>
                <motion.div
                  key={checked ? "dark" : "light"}
                  initial={{ opacity: 0, scale: 0.5, rotate: -90 }}
                  animate={{ opacity: 1, scale: 1, rotate: 0 }}
                  exit={{ opacity: 0, scale: 0.5, rotate: 90 }}
                  transition={{ 
                    type: "spring", 
                    stiffness: 300, 
                    damping: 20 
                  }}
                  style={{ position: 'absolute' }}
                >
                  <span className="iconify" data-icon={checked ? "solar:sun-bold-duotone" : "solar:moon-bold-duotone"}></span>
                </motion.div>
              </AnimatePresence>
            </motion.div>
          </div>
        </motion.nav>

        {/* Background Glow */}
        <motion.div 
          animate={{ scale: [1, 1.2, 1], opacity: [0.1, 0.15, 0.1] }}
          transition={{ duration: 10, repeat: Infinity, ease: "easeInOut" }}
          style={{
            position: "absolute", top: "30%", right: "15%", width: "500px", height: "500px",
            background: "radial-gradient(circle, #AE944F 0%, transparent 70%)",
            filter: "blur(100px)", zIndex: 0, pointerEvents: "none"
          }}
        />

        <div className="row aligner" style={{ height: '100%', margin: 0 }}>
          <motion.div 
            className="col-md-12"
            initial="hidden"
            animate="visible"
            variants={containerVariants}
            style={{ zIndex: 1 }}
          >
            <div>
              <motion.div
                animate={{ y: [0, -15, 0] }}
                transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
              >
                <span className="iconify header-icon" data-icon="la:laptop-code" style={{ color: 'var(--header-text)' }}></span>
              </motion.div>

              <br />

              <motion.h1 
                className="mb-0" 
                variants={childVariants}
                style={{ color: 'var(--header-text)', fontWeight: '700', fontSize: '4rem' }}
              >
                {name}
              </motion.h1>

              <motion.div className="title-container" variants={childVariants} style={{ height: '40px' }}>
                {titles.length > 0 && (
                  <AnimatedTitles titles={titles} />
                )}
              </motion.div>
            </div>
          </motion.div>
        </div>

        {/* Scroll indicator */}
        {!isScrolled && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1, y: [0, 10, 0] }}
            transition={{ delay: 2, duration: 2, repeat: Infinity }}
            style={{
              position: "absolute", bottom: "40px", left: "50%", transform: "translateX(-50%)",
              cursor: "pointer", color: "#AE944F", fontSize: "2.5rem", zIndex: 10
            }}
            onClick={(e) => this.scrollToSection(e, "about")}
          >
            <span className="iconify" data-icon="bi:chevron-double-down"></span>
          </motion.div>
        )}
      </header>
    );
  }
}

export default Header;
